import classes from "./AvatarWrapper.module.css";

const AvatarWrapper = (props) => {
  return (
    <div className={classes["avatar-wrapper"]}>
      <img
        className={classes["avatar-image"]}
        src={props.image}
        alt=" "
      ></img>
    </div>
  );
};

export default AvatarWrapper;
